tasks.solution:
# index.js
const http = require('http');
const server = http.createServer((req, res) => {
  res.writeHead(200);
  res.end('Hello from container!');
});
server.listen(8080, () => console.log('Listening on port 8080'));

# package.json
{
  "name": "myapp",
  "version": "1.0.0",
  "scripts": { "start": "node index.js" }
}

# Dockerfile
FROM node:20-alpine
WORKDIR /app
COPY package.json ./
RUN npm install
COPY . .
EXPOSE 8080
CMD ["node", "index.js"]

# .dockerignore
node_modules
.git
*.env

# 빌드 및 실행:
docker build -t myapp:local .
docker run -p 5000:8080 myapp:local
# http://localhost:5000을 열면 'Hello from container!'가 반환된다
